mapper.insert:
insert into makeup_exam

    score_entry_id
    exam_date
    start_time
    end_time

    values

    #{scoreEntryId}
    #{examDate}
    #{startTime}
    #{endTime}

mapper.update:
update makeup_exam

        exam_date = #{examDate}
        start_time = #{startTime}
        end_time = #{endTime}
        status = #{status}

where id = #{id}

mapper.select:
select m.id, c.course_name, m.exam_date, m.start_time, m.end_time, m.status
from makeup_exam m
join score_entry se on m.score_entry_id = se.id
join course c on se.course_id = c.id

    se.student_id = #{userId}
    and m.status = #{status}
